/**
 * Tests for the value-ordered inlined-numeric id encoding: round-trips per subtype, the order property (id value fields
 * compare like the numbers), writer gating via the persisted store property, and legacy-store coexistence.
 */
public class LmdbOrderedNumericIdsTest {

	private static final ValueFactory VF = SimpleValueFactory.getInstance();

	private static long orderedId(Literal literal) {
		long id = Values.packLiteral(literal, true);
		assertThat(id).as("literal must inline: %s", literal).isNotZero();
		return id;
	}

	@Test
	public void orderedRoundTripsAllSignedSubtypes() {
		Literal[] literals = {
				VF.createLiteral(BigInteger.valueOf(-123456789L)),
				VF.createLiteral(BigInteger.ZERO),
				VF.createLiteral(-42L),
				VF.createLiteral(42),
				VF.createLiteral((short) -7),
				VF.createLiteral((byte) -1),
				VF.createLiteral("17", XSD.POSITIVE_INTEGER),
				VF.createLiteral("-17", XSD.NEGATIVE_INTEGER),
				VF.createLiteral("0", XSD.NON_NEGATIVE_INTEGER),
				VF.createLiteral("0", XSD.NON_POSITIVE_INTEGER),
		};
		for (Literal literal : literals) {
			long id = orderedId(literal);
			assertThat(ValueIds.isOrderedInteger(id)).as("ordered code for %s", literal).isTrue();
			assertThat(Values.unpackLiteral(id, VF)).isEqualTo(literal);
		}
	}

	@Test
	public void orderedRoundTripsBoundaryValues() {
		long maxInline = (1L << 55) - 1;
		long minInline = -(1L << 55);
		for (long value : new long[] { minInline, minInline + 1, -1, 0, 1, maxInline - 1, maxInline,
				Long.MIN_VALUE + 1 }) {
			Literal literal = VF.createLiteral(BigInteger.valueOf(value));
			long id = Values.packLiteral(literal, true);
			if (value < minInline || value > maxInline) {
				assertThat(id).as("out-of-range value must not inline: %d", value).isZero();
				continue;
			}
			assertThat(Values.unpackLiteral(id, VF)).isEqualTo(literal);
			assertThat(ValueIds.orderedIntegerValue(id)).isEqualTo(value);
		}
	}

	@Test
	public void idValueFieldsCompareLikeTheNumbers() {
		long[] values = { -(1L << 55), -1_000_000, -2, -1, 0, 1, 2, 999, 1_000_000, (1L << 55) - 1 };
		long previousField = Long.MIN_VALUE;
		for (long value : values) {
			long id = orderedId(VF.createLiteral(BigInteger.valueOf(value)));
			long field = ValueIds.getValue(id);
			assertThat(field).as("value field of %d must exceed the previous smaller value's", value)
					.isGreaterThan(previousField);
			previousField = field;
		}
		// cross-subtype: same axis, so 5^^xsd:int vs 7^^xsd:long rank correctly via the value fields
		long five = orderedId(VF.createLiteral(5));
		long seven = orderedId(VF.createLiteral(7L));
		assertThat(ValueIds.getValue(five)).isLessThan(ValueIds.getValue(seven));
		assertThat(ValueIds.orderedIntegerValue(five)).isEqualTo(5);
		assertThat(ValueIds.orderedIntegerValue(seven)).isEqualTo(7);
	}

	@Test
	public void legacyModeKeepsZigZagCodes() {
		Literal literal = VF.createLiteral(42);
		long legacy = Values.packLiteral(literal, false);
		long ordered = Values.packLiteral(literal, true);
		assertThat(ValueIds.getIdType(legacy)).isEqualTo(ValueIds.T_INT);
		assertThat(ValueIds.getIdType(ordered)).isEqualTo(ValueIds.T_ORD_INT);
		assertThat(ValueIds.isOrderedInteger(legacy)).isFalse();
		// both decode to the same literal: the encodings coexist in one store
		assertThat(Values.unpackLiteral(legacy, VF)).isEqualTo(Values.unpackLiteral(ordered, VF)).isEqualTo(literal);
	}

	@Test
	public void newStoreRecordsOrderedEncodingAndServesQueries(@TempDir File dataDir) {
		SailRepository repository = new SailRepository(new LmdbStore(dataDir, new LmdbStoreConfig("spoc,posc")));
		try {
			try (SailRepositoryConnection connection = repository.getConnection()) {
				connection.begin();
				for (int i = 0; i < 20; i++) {
					IRI subject = connection.getValueFactory().createIRI("http://example.com/s" + i);
					connection.add(subject, connection.getValueFactory().createIRI("http://example.com/value"),
							connection.getValueFactory().createLiteral(i - 10));
				}
				connection.commit();
			}
			try (SailRepositoryConnection connection = repository.getConnection()) {
				List<BindingSet> result = QueryResults.asList(connection.prepareTupleQuery(
						"SELECT ?s ?v WHERE { ?s <http://example.com/value> ?v . FILTER(?v > 5) }").evaluate());
				assertThat(result).hasSize(4); // values 6..9
				for (BindingSet row : result) {
					Literal value = (Literal) row.getValue("v");
					assertThat(value.intValue()).isGreaterThan(5);
					assertThat(value).isInstanceOf(LmdbValue.class);
					assertThat(ValueIds.isOrderedInteger(((LmdbValue) value).getInternalID()))
							.as("ordered-v1 reads must expose the persisted ordered integer id")
							.isTrue();
				}
			}
		} finally {
			repository.shutDown();
		}
		StoreProperties properties = new StoreProperties(dataDir);
		properties.load();
		assertThat(properties.getVersion()).isEqualTo("3");
		assertThat(properties.usesOrderedNumericIds()).isTrue();
	}

	@Test
	public void legacyStoreKeepsLegacyEncodingAcrossUpgrade(@TempDir File dataDir) throws Exception {
		// create a real store first, then rewrite its properties to look like a pre-ordered-encoding v2 store
		// (version 2, triple indexes recorded, no numeric-id-encoding key)
		SailRepository bootstrap = new SailRepository(
				new LmdbStore(dataDir, new LmdbStoreConfig("spoc,posc").setOrderedNumericIds(false)));
		bootstrap.getConnection().close();
		bootstrap.shutDown();
		StoreProperties legacy = new StoreProperties(dataDir);
		legacy.load();
		assertThat(legacy.usesOrderedNumericIds()).isFalse();
		legacy.setVersion("2");
		legacy.save();

		SailRepository repository = new SailRepository(new LmdbStore(dataDir, new LmdbStoreConfig("spoc,posc")));
		try (SailRepositoryConnection connection = repository.getConnection()) {
			connection.begin();
			connection.add(connection.getValueFactory().createIRI("http://example.com/s"),
					connection.getValueFactory().createIRI("http://example.com/value"),
					connection.getValueFactory().createLiteral(42));
			connection.commit();
			List<BindingSet> result = QueryResults.asList(connection.prepareTupleQuery(
					"SELECT ?v WHERE { ?s ?p ?v }").evaluate());
			assertThat(result).hasSize(1);
			assertThat(((Literal) result.get(0).getValue("v")).intValue()).isEqualTo(42);
		} finally {
			repository.shutDown();
		}

		StoreProperties reloaded = new StoreProperties(dataDir);
		reloaded.load();
		assertThat(reloaded.getVersion()).as("version upgrades in place").isEqualTo("3");
		assertThat(reloaded.usesOrderedNumericIds())
				.as("an upgraded legacy store must never adopt the ordered encoding")
				.isFalse();
	}
}
